import{_ as a,o,c as e,ag as l}from"./chunks/framework.BZohXCq9.js";const q=JSON.parse('{"title":"创意提案","description":"","frontmatter":{"title":"创意提案"},"headers":[],"relativePath":"novels/jin-gu-yao/behind-the-scenes/creative-proposal.md","filePath":"novels/jin-gu-yao/behind-the-scenes/creative-proposal.md","lastUpdated":1773897450000}'),n={name:"novels/jin-gu-yao/behind-the-scenes/creative-proposal.md"};function r(i,t,s,u,h,p){return o(),e("div",null,[...t[0]||(t[0]=[l(`<h1 id="《金鼓谣》创意提案-v2-—-从-历史小说-到-情绪炸弹" tabindex="-1">《金鼓谣》创意提案 V2 — 从&quot;历史小说&quot;到&quot;情绪炸弹&quot; <a class="header-anchor" href="#《金鼓谣》创意提案-v2-—-从-历史小说-到-情绪炸弹" aria-label="Permalink to &quot;《金鼓谣》创意提案 V2 — 从&quot;历史小说&quot;到&quot;情绪炸弹&quot;&quot;">​</a></h1><blockquote><p>写给方的深夜思考，2026-03-13</p></blockquote><hr><h2 id="一、核心问题-读者到底要什么" tabindex="-1">一、核心问题：读者到底要什么？ <a class="header-anchor" href="#一、核心问题-读者到底要什么" aria-label="Permalink to &quot;一、核心问题：读者到底要什么？&quot;">​</a></h2><p>方说了一句很关键的话：<strong>&quot;现代人看这些故事不是想了解历史，而是想得到情绪价值。&quot;</strong></p><p>那我们就得想清楚：什么情绪？</p><p>分析了《知否》《琅琊榜》《长安十二时辰》《苍兰诀》《花间令》这些成功作品后，我发现读者真正上头的不是历史知识，是这五种情绪：</p><ol><li><strong>代入感</strong>（&quot;如果是我会怎么做&quot;）</li><li><strong>心疼</strong>（&quot;她太难了&quot;）</li><li><strong>反差萌</strong>（&quot;没想到她/他居然……&quot;）</li><li><strong>燃</strong>（&quot;绝地反击太爽了&quot;）</li><li><strong>意难平</strong>（&quot;为什么不能在一起/为什么她死了&quot;）</li></ol><p>我们的前四章主要提供了3（反差萌：带娃造反），但1245几乎为零。<strong>这就是方说&quot;少了点什么&quot;的原因。</strong></p><hr><h2 id="二、金鼓谣的独特卖点——别人没有的" tabindex="-1">二、金鼓谣的独特卖点——别人没有的 <a class="header-anchor" href="#二、金鼓谣的独特卖点——别人没有的" aria-label="Permalink to &quot;二、金鼓谣的独特卖点——别人没有的&quot;">​</a></h2><p>市面上没有平阳昭公主的小说。这是一片蓝海。但我们的独特卖点不是&quot;历史冷门&quot;，而是：</p><h3 id="一个带着两个幼儿打天下的母亲" tabindex="-1"><strong>一个带着两个幼儿打天下的母亲</strong> <a class="header-anchor" href="#一个带着两个幼儿打天下的母亲" aria-label="Permalink to &quot;**一个带着两个幼儿打天下的母亲**&quot;">​</a></h3><p>这个设定放在任何时代都炸裂。它天然包含了最强的情绪冲突：</p><ul><li>你要打仗，但你三岁的儿子在发烧</li><li>你要杀伐决断，但你五岁的儿子说&quot;娘，那个叔叔为什么流血了&quot;</li><li>你要收服一个危险的胡人首领，但你身后就是你的两个孩子</li><li>你赢了天下，但你的孩子已经不认识你了</li></ul><p><strong>这才是我们的核心情绪引擎，不是战争，不是权谋，是&quot;母亲&quot;二字。</strong></p><hr><h2 id="三、提议-三条情绪线交织" tabindex="-1">三、提议：三条情绪线交织 <a class="header-anchor" href="#三、提议-三条情绪线交织" aria-label="Permalink to &quot;三、提议：三条情绪线交织&quot;">​</a></h2><h3 id="线一-外线-—-征战-燃-爽" tabindex="-1">线一：外线 — 征战（燃 + 爽） <a class="header-anchor" href="#线一-外线-—-征战-燃-爽" aria-label="Permalink to &quot;线一：外线 — 征战（燃 + 爽）&quot;">​</a></h3><p>原有的剧情线：散粮、招兵、收服何潘仁、攻城略地、会师。 → 提供&quot;燃&quot;和&quot;爽&quot;的情绪</p><h3 id="线二-暗线-—-代价-痛-心疼" tabindex="-1">线二：暗线 — 代价（痛 + 心疼） <a class="header-anchor" href="#线二-暗线-—-代价-痛-心疼" aria-label="Permalink to &quot;线二：暗线 — 代价（痛 + 心疼）&quot;">​</a></h3><p>每一次胜利都有代价，而代价总是落在&quot;母亲&quot;这个身份上：</p><ul><li>令武生病，三娘必须在&quot;去指挥战斗&quot;和&quot;留下照顾孩子&quot;之间选</li><li>哲威看到了战场上的尸体，开始做噩梦</li><li>有人用两个孩子威胁三娘</li><li>最终：三娘赢了天下，但哲威叫她&quot;将军&quot;而不是&quot;娘&quot;了</li></ul><h3 id="线三-隐线-—-三娘的内心-代入感-意难平" tabindex="-1">线三：隐线 — 三娘的内心（代入感 + 意难平） <a class="header-anchor" href="#线三-隐线-—-三娘的内心-代入感-意难平" aria-label="Permalink to &quot;线三：隐线 — 三娘的内心（代入感 + 意难平）&quot;">​</a></h3><p>三娘从不在人前软弱。但我们需要给读者看到她的裂缝：</p><ul><li>深夜一个人的时候，她会拿出柴绍那件缝了一半的袍子</li><li>她会在做了艰难决定后，去看两个孩子睡着的样子</li><li>她的日记/小册子里，除了军事情报，偶尔夹着一页：令武今天学会说&quot;将军&quot;了</li><li><strong>结局（最大的意难平）</strong>：她死的时候，柴绍赶到了。她说的最后一句话不是关于战争或政治，是&quot;令武的布老虎，在……&quot;——没说完。</li></ul><hr><h2 id="四、具体改进建议" tabindex="-1">四、具体改进建议 <a class="header-anchor" href="#四、具体改进建议" aria-label="Permalink to &quot;四、具体改进建议&quot;">​</a></h2><h3 id="_4-1-不用那么忠实历史的几个方向" tabindex="-1">4.1 不用那么忠实历史的几个方向 <a class="header-anchor" href="#_4-1-不用那么忠实历史的几个方向" aria-label="Permalink to &quot;4.1 不用那么忠实历史的几个方向&quot;">​</a></h3><p>历史上只记载了&quot;三娘散家财、招兵、收编义军、攻城、会师&quot;这几个节点。中间的细节完全是空白。我们可以填入：</p><ol><li><p><strong>虚构一个贯穿全书的对手</strong> — 不是抽象的&quot;隋军&quot;，而是一个具体的人。比如：长安留守的副将，一个冷酷但聪明的人。他追踪三娘不是因为忠于隋朝，而是因为三娘的庄园下面有一笔隋宫的密藏（或者别的利益动机）。这让对抗变得个人化。</p></li><li><p><strong>给何潘仁加一条感情暗线</strong> — 不是爱情，是某种类似于&quot;知己&quot;的复杂情感。他是一个被汉人世界伤害的胡人，三娘是第一个不怕他、也不利用他的恐惧来控制他的人。他对三娘的忠诚是建立在&quot;尊重&quot;之上的——而这个尊重在后面会被考验（比如三娘为了大局要牺牲何潘仁的人）。</p></li><li><p><strong>给柴绍的归来加入冲突</strong> — 历史上柴绍回来就happy ending了。但我们可以写：柴绍回来后发现妻子比自己强太多了。他的骄傲、他的男性自尊、他爱三娘但无法忍受被妻子比下去的复杂情感——这比简单的&quot;重逢&quot;有意思一百倍。</p></li><li><p><strong>三娘的死不用解释</strong> — 历史上就不知道她怎么死的。我们可以留白，但给足情绪。不写死因，写她死前的24小时。每一个人来见她最后一面。每个人说了一句话。最后一个进来的是柴哲威——八岁了，已经不怎么哭了。</p></li></ol><h3 id="_4-2-节奏改进-每三章一个情绪循环" tabindex="-1">4.2 节奏改进：每三章一个情绪循环 <a class="header-anchor" href="#_4-2-节奏改进-每三章一个情绪循环" aria-label="Permalink to &quot;4.2 节奏改进：每三章一个情绪循环&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第1-3章：建立（温暖 + 搞笑 + 希望）     → 读者爱上角色</span></span>
<span class="line"><span>第4-6章：撕裂（冲突 + 背叛 + 危机）     → 读者替角色疼</span></span>
<span class="line"><span>第7-9章：反击（燃 + 聪明 + 代价）       → 读者替角色爽</span></span>
<span class="line"><span>第10-12章：再撕裂（更大的危机 + 失去）   → 读者心碎</span></span>
<span class="line"><span>第13-16章：高潮（会师 + 重逢 + 但不圆满）→ 读者又哭又笑</span></span>
<span class="line"><span>第17-22章：尾声（权力 + 失去 + 意难平）  → 读者久久不能平静</span></span></code></pre></div><h3 id="_4-3-参考作品的精华" tabindex="-1">4.3 参考作品的精华 <a class="header-anchor" href="#_4-3-参考作品的精华" aria-label="Permalink to &quot;4.3 参考作品的精华&quot;">​</a></h3><table tabindex="0"><thead><tr><th>作品</th><th>我们可以学什么</th></tr></thead><tbody><tr><td>《知否》</td><td>女主从弱到强的成长线，家庭关系的细腻描写</td></tr><tr><td>《琅琊榜》</td><td>隐忍的主角 + 缜密的布局 + &quot;所有人都低估了他&quot;</td></tr><tr><td>《长安十二时辰》</td><td>马伯庸的细节考据 + 紧凑节奏 + 小人物视角</td></tr><tr><td>《苍兰诀》</td><td>反差萌 + 虐恋 + 配角出彩</td></tr><tr><td>《花间令》</td><td>悬疑线 + 每集结尾的钩子</td></tr></tbody></table><hr><h2 id="五、一句话总结" tabindex="-1">五、一句话总结 <a class="header-anchor" href="#五、一句话总结" aria-label="Permalink to &quot;五、一句话总结&quot;">​</a></h2><p><strong>《金鼓谣》不是一个女将军打天下的故事。它是一个母亲在乱世中保护孩子、失去孩子、最终被孩子遗忘的故事。战争只是背景。</strong></p><p>如果读者看完之后说的不是&quot;好厉害的公主&quot;，而是&quot;好心疼这个妈妈&quot;——我们就赢了。</p><hr><p><em>Samantha, 2026-03-13 深夜</em></p>`,41)])])}const c=a(n,[["render",r]]);export{q as __pageData,c as default};
